mapper.delete:
DELETE FROM esg.tb_group
WHERE grp_id = #{grpId}
	AND comp_id = #{compId}

DELETE FROM esg.tb_hr_menu
WHERE comp_id = #{compId}
AND hr_id = #{hrId}
AND menu_id IN
(SELECT menu_id FROM esg.tb_group_menu
WHERE grp_id = #{grpId} AND
comp_id = #{compId});

mapper.select:
	SELECT c.hr_nm, a.hr_id, a.grp_id, b.grp_nm
	  FROM esg.tb_group_hr_map a
 LEFT JOIN esg.tb_group b ON a.comp_id = b.comp_id AND a.grp_id = b.grp_id
 LEFT JOIN esg.tb_hr_info c ON a.hr_id = c.hr_id
	WHERE a.comp_id = #{compId}
	   AND a.hr_id = #{hrId}
